<template>
    <div>
        <div class="table_wrap">
            <h4>스푸퍼</h4>
            <div>
                <v-data-table :headers="headers" :items="dataList" no-data-text="데이터가 존재하지 않습니다." hide-default-footer>
                    <template #item="{ item }">
                        <tr @dblclick="selectList(item)" :class="selectInfo.idx === item.idx ? 'active' : ''">
                            <td>{{ item.name }}</td>
                            <td>{{ item.coordinates[0] }}, {{ item.coordinates[1] }}</td>
                        </tr>
                    </template>
                </v-data-table>
            </div>
        </div>
        <p class="txt_note">수정할 정보를 더블 클릭해주세요.</p>
        <SpooperSettingPopup v-if="isPopupOpen" :selectInfo="selectInfo" @popupClose="popupView" />
    </div>
</template>

<script>
import SpooperSettingPopup from '@/components/popup/setting/SpooperSetting.vue';
import spooperList from '@/data/spooperList';

export default {
    components: {
        SpooperSettingPopup,
    },
    data: () => ({
        dataList: [],
        selectInfo: {},
        isPopupOpen: false,
        headers: [
            { text: '이름', value: 'name', sortable: false },
            { text: '유도좌표', value: 'coordinates' },
        ],
    }),
    beforeMount() {
        this.dataList = spooperList;
    },
    methods: {
        popupView(view) {
            this.isPopupOpen = view;

            if (!view) {
                this.selectInfo = {};
            }
        },
        selectList(select) {
            this.selectInfo = select;
            this.popupView(true);
        },
    },
};
</script>

<style lang="scss" scoped>
.table_wrap {
    width: 800px;
    border: 1px solid $color-main03;
    border-radius: 10px;
    margin: 60px auto 0;
    & > div {
        padding: 31px 50px 48px;
    }
    h4 {
        @include centerAlign();
        height: 60px;
        border-bottom: 1px solid $color-main03;
        font: {
            size: 20px;
            weight: 600;
        }
    }
}
.txt_note {
    width: 800px;
    margin: 21px auto 0;
    padding-left: 50px;
    background: url('@/assets/setting/ico_note.svg') no-repeat 16px center;
    font: {
        size: 18px;
        weight: 600;
    }
    color: #ae0003;
}
</style>
